// Flash Ventas 360 — instalar en github/
const fs=require('fs'),path=require('path');
const pub=path.join(__dirname,'public');
fs.mkdirSync(pub,{recursive:true});
fs.writeFileSync(path.join(pub,'flash-module.js'),Buffer.from('','base64'));
console.log('✓ flash-module.js:',fs.statSync(path.join(pub,'flash-module.js')).size,'bytes');
fs.writeFileSync(path.join(pub,'app.js'),Buffer.from('','base64'));
console.log('✓ app.js:',fs.statSync(path.join(pub,'app.js')).size,'bytes');
fs.writeFileSync(path.join(pub,'index.html'),Buffer.from('','base64'));
console.log('✓ index.html:',fs.statSync(path.join(pub,'index.html')).size,'bytes');
console.log('');
console.log('git add public/flash-module.js public/app.js public/index.html');
console.log('git commit -m "Add: Flash Ventas 360"');
console.log('git push origin main');
